import React, { useState } from "react";
import "../../styles/Todo.css";
import TodoModal from "./TodoModal";

const uid = () => Date.now() + Math.random();

const Todo = () => {
    const [todos, setTodos] = useState([]);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingTodo, setEditingTodo] = useState(null);

    const openModal = () => {
        setEditingTodo(null);
        setIsModalOpen(true);
    };

    const openEditModal = (todo) => {
        setEditingTodo(todo);
        setIsModalOpen(true);
    };

    const handleSaveTodo = ({ text, category }) => {
        if (editingTodo) {
            setTodos((prev) =>
                prev.map((t) =>
                    t.id === editingTodo.id ? { ...t, text, category } : t
                )
            );
        } else {
            setTodos((prev) => [
                ...prev,
                { id: uid(), text, category, completed: false },
            ]);
        }

        setIsModalOpen(false);
    };

    const handleDeleteTodo = () => {
        if (!editingTodo) return;
        setTodos((prev) => prev.filter((t) => t.id !== editingTodo.id));
        setIsModalOpen(false);
    };

    return (
        <div className="todo-container">
            <div className="todo-header">
                <div className="todo-title">To do List</div>
                <button className="todo-add" onClick={openModal}>
                    +
                </button>
            </div>

            <div className="todo-list">
                {todos.map((t) => (
                    <div
                        key={t.id}
                        className="todo-item"
                        onClick={() => openEditModal(t)}
                    >
                        <div className="todo-text">{t.text}</div>
                        <div className="todo-category">{t.category}</div>
                    </div>
                ))}
            </div>

            <TodoModal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                onSave={handleSaveTodo}
                onDelete={handleDeleteTodo}
                initialTodo={editingTodo}
            />
        </div>
    );
};

export default Todo;
